(function (factory) {
	typeof define === 'function' && define.amd ? define(factory) :
	factory();
})((function () { 'use strict';

	const Sidebar = {
		init(app) {
			// save reference to app
			this.app = app;
		},
		dispatch(event) {
			let Self = Sidebar,
				App = Self.app,
				el;
			// console.log(event);
			switch (event.type) {
				case "init-tree":
					// set leaf id
					App.ledger.selectNodes(`//Tree//*`).map((xLeaf, i) => xLeaf.setAttribute("_id", i+1));
					// auto render tree
					App.dispatch({
						type: "render-template",
						template: "tree",
						match: `//Tree`,
						target: App.els.layout.find(".sidebar"),
					});
					break;
				case "select-tree-item":
					el = $(event.orgEvent.target);
					if (el.hasClass("icon-chevron-right")) {
						let leaf = el.parents(".leaf").get(0);
						let target = leaf.find(".children:first");
						if (!target[0].childNodes.length) {
							// render childnodes
							App.dispatch({
								type: "render-template",
								template: "tree",
								match: `//Tree//*[@_id="${leaf.data("id")}"]`,
								target,
							});
						}
						setTimeout(() => leaf.toggleClass("open", leaf.hasClass("open")), 20);
						return;
					}
					// get leaf item
					el = event.el.parents("?.leaf").get(0);
					if (!el.length) return;
					// local stored state
					if (el.find("> span").data("type") != "xml") {
						// UI update
						App.els.sidebar.find(".active").removeClass("active");
						el.addClass("active");

						console.log(1);

						return;
					}

					// toggle folder icon
					if (el.find("> span").data("type") != "xml") {
						return el.find("> span > i.icon-chevron-right").trigger("click");
					}
					// UI update
					App.els.sidebar.find(".active").removeClass("active");
					el.addClass("active");

					let folder = el.parents(".leaf").get(0).find("> span > b").text(),
						name = el.find("> span > b").text(),
						type = el.find("> span").data("type");
					if (type) {
						$.fetch(`../tests/fixture/${folder}/${name}.${type}`)
							.then(res => App.editor.dispatch({ type: "parse-xml-fixture", res }));
					}
					break;
			}
		}
	};


	const Toolbar = {
		init(app) {
			// save reference to app
			this.app = app;
		},
		dispatch(event) {
			let Self = Toolbar,
				App = Self.app,
				value;
			// console.log(event);
			switch (event.type) {
				case "toggle-sidebar":
					value = App.els.layout.hasClass("hide-sidebar");
					App.els.layout.toggleClass("hide-sidebar", value);
					break;
				case "toggle-info":
					value = App.els.layout.hasClass("show-info");
					App.els.layout.toggleClass("show-info", value);
					break;
				case "toggle-theme":
					value = event.el.hasClass("on") ? "dark" : "light";
					App.els.body.data({ theme: value });
					break;
				case "set-processor":
					App.output.dispatch(event);
					break;
			}
		}
	};


	const Resize = {
		init(app) {
			// save reference to app
			this.app = app;
			// fast references
			this.els = {
				doc: $(document),
				body: $("body"),
			};
			// resize constraints for areas
			this.constrains = {
				"sidebar": { min: { x: 100 }, max: { x: 300 } },
				"xml-doc": { min: { x: 500 }, max: { x: 1050 } },
				"workarea": { min: { y: 600 }, max: { y: 1050 } },
			};
			// bind event handlers
			$(".divider").on("mousedown", this.dispatch);
		},
		dispatch(event) {
			let Drag = Resize.drag,
				data = {};
			switch (event.type) {
				case "mousedown":
					// prevent default behaviour
					event.preventDefault();
					// element info
					let org = $(event.target),
						dir = org.prop("className").split(" ")[1];
					// locked divider
					if (!org.prop("className").includes("divider") || org.prop("className").includes("locked")) return;
					// collect info
					let bEl = org.prevAll("div:first"),
						aEl = org.nextAll("div:first"),
						off = org.offset(),
						el = org.clone().addClass("clone").css(off),
						click = {
							x : event.clientX - off.left - event.offsetX - 14,
							y : event.clientY - off.top - event.offsetY - 14,
						},
						{ min, max } = Resize.constrains[bEl.prop("className").split(" ")[0]];
					// insert clone in to DOM and cover body
					Resize.els.body.addClass("covered").append(el);
					el = Resize.els.body.find(".clone");
					// safe drag details
					Resize.drag = { el, bEl, aEl, dir, click, off, min, max };
					// bind more event handlers
					Resize.els.doc.bind("mousemove mouseup", Resize.dispatch);
					break;
				case "mousemove":
					if (Drag.dir === "vertical") {
						data.left = Math.min(Drag.max.x, Math.max(Drag.min.x, event.clientX + Drag.click.x));
					} else { // horisontal
						data.top = Math.min(Drag.max.y, Math.max(Drag.min.y, event.clientY + Drag.click.y));
					}
					Drag.el.css(data);
					break;
				case "mouseup":
					if (Drag.dir === "vertical") {
						let offset = Drag.el.offset(),
							diff = offset.left - Drag.off.left,
							bW = Drag.bEl.width() + diff - 7,
							aW = Drag.aEl.width() - diff - 7;
						Drag.bEl.css({ width: bW });
						Drag.aEl.css({ width: aW });
					} else { // horisontal
						let offset = Drag.el.offset(),
							diff = offset.top - Drag.off.top,
							bH = Drag.bEl.height() + diff - 7,
							aH = Drag.aEl.height() - diff - 7;
						Drag.bEl.css({ height: bH });
						Drag.aEl.css({ height: aH });
					}
					// delete clone from DOM
					Drag.el.remove();
					// reset body
					Resize.els.body.removeClass("covered");
					// unbind more event handlers
					Resize.els.doc.unbind("mousemove mouseup", Resize.dispatch);
					break;
			}
		}
	};

	const Editor = {
		init(app) {
			// save reference to app
			this.app = app;
			// fast references
			this.els = {
				info: $(".description span"),
				xmlDoc: $(".xml-doc textarea"),
				xsltDoc: $(".xslt-doc textarea"),
				xmlDocState: $(".xml-doc .doc-state"),
				xsltDocState: $(".xslt-doc .doc-state"),
			};
			// empty textarea content
			$("textarea").val("");
		},
		dispatch(event) {
			let Self = Editor;
				Self.app;
			// console.log(event);
			switch (event.type) {
				// native events
				case "keyup":
					let xmlDoc;
					let xslDoc;
					// try to import xml data
					try {
						xmlDoc = $.xmlFromString(Self.xmlEditor.getValue());
					} catch (err) {
						Self.els.xmlDocState.removeClass("valid").addClass("invalid");
						return;
					}
					Self.els.xmlDocState.removeClass("invalid").addClass("valid");

					// try to import template
					try {
						// Self.templates = $.xmlFromString(tmp);
						xslDoc = $.xmlFromString(Self.xsltEditor.getValue());
					} catch (err) {
						Self.els.xsltDocState.removeClass("valid").addClass("invalid");
						return;
					}
					Self.els.xsltDocState.removeClass("invalid").addClass("valid");
					
					Self.xDoc = xmlDoc;
					Self.templates = xslDoc;
					Output.processor.importStylesheet(Self.templates.documentElement);
					// render xslt
					Output.dispatch({ type: "render-xslt" });
					break;
				// custom events
				case "parse-xml-fixture":
					let template = event.res.selectSingleNode("//Template");
					let xsltStr = template.textContent.trim();
					Self.templates = $.xmlFromString(xsltStr);
					// extract description
					let description = event.res.selectSingleNode("//Description");
					Self.els.info.html(description.textContent);
					// import templates
					Output.processor.importStylesheet(Self.templates.documentElement);
					// save reference xml doc
					Self.xDoc = $.xmlFromString(event.res.selectSingleNode("//XmlData/*").xml);

					Self.xmlEditor.setValue(Self.xDoc.xml);
					Self.xsltEditor.setValue(xsltStr);

					// render xslt
					Output.dispatch({ type: "render-xslt" });
					break;
				case "init-editors":
					Self.xmlEditor = CodeMirror.fromTextArea(Self.els.xmlDoc[0], { mode: "text/html", lineNumbers: true });
					Self.xsltEditor = CodeMirror.fromTextArea(Self.els.xsltDoc[0], { mode: "text/html", lineNumbers: true });
					Output.htmlView = CodeMirror.fromTextArea(Output.els.html[0], { mode: "text/html", lineNumbers: true, readOnly: true });
					// attache event handlers
					Self.xmlEditor.on("keyup", e => Self.dispatch({ type: "keyup", event: e }));
					Self.xsltEditor.on("keyup", e => Self.dispatch({ type: "keyup", event: e }));
					break;
			}
		}
	};


	const Output = {
		init(app) {
			// save reference to app
			this.app = app;
			// fast references
			this.els = {
				output: $(".output"),
				html: $(".output .html textarea"),
				rendered: $(".output .rendered"),
			};
			// set processor
			this.dispatch({ type: "set-processor" });
		},
		dispatch(event) {
			let Self = Output;
				Self.app;
			// console.log(event);
			switch (event.type) {
				case "set-processor":
					Self.useProxslt = (event.arg || "pro-xslt") === "pro-xslt";
					Self.processor = Self.useProxslt ? new ProXslt : new XSLTProcessor;
					if (!Editor.templates) return;
					// import templates
					Self.processor.importStylesheet(Editor.templates.documentElement);
					// re-render xslt
					Self.dispatch({ type: "render-xslt" });
					break;
				case "set-output-mode":
					Self.els.output.data({ view: event.arg });
					break;
				case "render-xslt":
					let span = document.createElement("span");
				    Editor.templates.selectSingleNode(`//xsl:template`); // [@name='${event.template}']
				    let fragment = Self.processor.transformToFragment(Editor.xDoc, document);
					
					if (fragment) span.appendChild(fragment);
					Output.htmlView.setValue(span.innerHTML);
					Output.els.rendered.html(span.innerHTML);
					break;
			}
		}
	};

	(() => {

	const App = {
		init() {
			// fast references
			this.els = {
				body: $("body"),
				layout: $(".layout"),
				sidebar: $(".sidebar"),
			};
			// init modules
			Object.keys(this).map(mod => this[mod].init ? this[mod].init(this) : void 0);
			// init editors
			this.editor.dispatch({ type: "init-editors" });
			// init app
			this.dispatch({ type: "load-ledger" });
			// bind event handlers
			$(document).on("click", "[data-click]", this.dispatch);
		},
		dispatch(event) {
			let Self = App,
				type,
				arg,
				pEl,
				el;
			// console.log(event);
			switch (event.type) {
				// native events
				case "click":
					el = $(event.target);
					type = el.parents("?[data-click]").data("click");
					if (el.hasClass("disabled")) return;
					// prevent default behaviour
					event.stopPropagation();
					event.preventDefault();

					if ((el.hasClass("tool") && el.hasClass("toggle")) || el.hasClass("boolean")) {
						let isOn = el.hasClass("on");
						el.toggleClass("on", isOn);
					}
					if (el.parent().hasClass("options")) {
						if (el.hasClass("on")) return;
						el.parent().find(".on").removeClass("on");
						el.addClass("on");
					}

					if (el.data("arg")) {
						arg = el.data("arg");
					}

					pEl = el.parents("?[data-area]");
					if (pEl.length) {
						// proxy event
						Self[pEl.data("area")].dispatch({ el, type, arg, orgEvent: event });
					} else {
						// falls through
						Self.dispatch({ el, type, arg, orgEvent: event });
					}
					break;
				// custom events
				case "load-ledger":
					$.fetch("./xml/ledger.xml").then(xDoc => {
						let templates = xDoc.selectSingleNode("//xsl:stylesheet");
						Self.templates = $.xmlFromString(templates.xml);
						templates.parentNode.removeChild(templates);
						// import templates
						Self.processor = new ProXslt;
						Self.processor.importStylesheet(Self.templates.documentElement);
						// save reference to ledger
						Self.ledger = xDoc.documentElement;
						// console.log(Self.ledger);

						// render tree
						Self.sidebar.dispatch({ type: "init-tree" });

						// temp test
						setTimeout(() => Self.els.layout.find(".leaf").get(0).trigger("click"), 200);
					});
					break;
				case "render-template":
					let span = document.createElement("span");
				    let template = Self.templates.selectSingleNode(`//xsl:template[@name='${event.template}']`);
				    template.setAttribute("match", event.match);
				    let fragment = Self.processor.transformToFragment(Self.ledger, document);
				    template.removeAttribute("match");
					
					if (fragment) span.appendChild(fragment);
					event.target.html(span.innerHTML);
					break;
			}
		},
		resize: Resize,
		toolbar: Toolbar,
		sidebar: Sidebar,
		editor: Editor,
		output: Output,
	};

	// init App
	$.ready_(() => App.init());

	// temp
	window.App = App;

	})();

}));
